package ru.memearena.meme.api; import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import jakarta.validation.constraints.*; import org.springframework.http.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*; import ru.memearena.meme.application.MemeService; import ru.memearena.ranking.api.*; import ru.memearena.ranking.application.RankingService; import ru.memearena.ratelimit.RateLimiterService; import ru.memearena.security.AuthenticatedUserPrincipal; import java.util.UUID;
@RestController @RequestMapping("/api/v1/memes") public class MemeController { private final MemeService memes; private final RankingService ranking; private final RateLimiterService limits; public MemeController(MemeService memes,RankingService ranking,RateLimiterService limits){this.memes=memes;this.ranking=ranking;this.limits=limits;} @PostMapping @Operation(summary="Create meme") public ResponseEntity<MemeResponse> create(@AuthenticationPrincipal AuthenticatedUserPrincipal p,@Valid @RequestBody CreateMemeRequest r){limits.check("meme-day",p.userId().toString(),20,86400); return ResponseEntity.status(HttpStatus.CREATED).body(MemeResponse.from(memes.create(p.userId(),r.title(),r.mediaAssetId(),r.imageUrl(),r.sourceUrl())));} @GetMapping("/{memeId}") @Operation(summary="Get meme") public MemeResponse get(@PathVariable UUID memeId){return MemeResponse.from(memes.get(memeId));} @GetMapping("/top") @Operation(summary="Get top memes") public TopMemesResponse top(@RequestParam(defaultValue="ALL_TIME") RankingPeriod period,@RequestParam(defaultValue="20") @Min(1) @Max(100) int limit){return ranking.top(period,limit);} }
